SELECT perms FROM yu_permission e WHERE EXISTS(
	SELECT a.permission_id FROM
	yu_role_permission a JOIN yu_role b ON a.role_id=b.role_id
	JOIN yu_user_role c ON c.role_id =b.role_id
	JOIN yu_user d ON c.user_id = d.user_id WHERE e.permission_id =a.permission_id AND e.perms is not null AND d.user_id=#{id}
) group by perms

select * from cc_common_task


		and type in (${type})


		and status = ${status}

mapper.update:
update cc_common_task set
error_msg=#{errorMsg}, last_run_time=#{lastRunTime},
where task_id=#{taskid}
